import requests
import base64

def build_saml_request(destination_url, user_info):
    saml_request = f'<samlRequest><user>{user_info}</user></samlRequest>'
    encoded_request = base64.b64encode(saml_request.encode()).decode()
    post_data = {'SAMLRequest': encoded_request}
    response = requests.post(destination_url, data=post_data)
    return response.text

